/**
 * Type to add the range prop defining any FilterField node.
 * @public
 */
export type SimpleFilterFieldNodeBase = {
    range?: {
        from: number;
        to: number;
    };
};
/**
 * Type used for defining the FilterField root node.
 * @public
 */
export type SimpleFilterFieldRootNode = SimpleFilterFieldGroupNode & {
    version?: string;
};
/**
 * Type used for defining a FilterField group node.
 * @public
 */
export type SimpleFilterFieldGroupNode = SimpleFilterFieldNodeBase & {
    type: 'Group';
    logicalOperator: 'AND' | 'OR';
    explicitLogicalOperator: boolean;
    explicit: boolean;
    children: SimpleFilterFieldNode[];
};
/**
 * Type used for defining a FilterField statement node.
 * @public
 */
export type SimpleFilterFieldStatementNode = SimpleFilterFieldNodeBase & {
    type: 'Statement';
    key?: SimpleFilterFieldKeyNode | SimpleFilterFieldJSONPathNode | (Omit<SimpleFilterFieldErrorNode, 'value'> & {
        value: string;
    });
    comparisonOperator?: SimpleFilterFieldLeafNode;
    value?: SimpleFilterFieldLeafNode | SimpleFilterFieldListNode;
};
/**
 * Type used for defining a FilterField key node.
 * @public
 */
export type SimpleFilterFieldKeyNode = SimpleFilterFieldNodeBase & {
    type: 'Key';
    textValue?: string;
    value: string;
};
/**
 * Type used for defining a FilterField JsonPath node.
 * @public
 */
export type SimpleFilterFieldJSONPathNode = SimpleFilterFieldNodeBase & {
    type: 'JSONPath';
    textValue: string;
    value: string;
    root: string;
    path: string;
};
/**
 * Type used for defining a FilterField IPAddress node.
 * @public
 */
export type SimpleFilterFieldIPAddressNode = SimpleFilterFieldNodeBase & {
    type: 'IPAddress';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField UID node.
 * @public
 */
export type SimpleFilterFieldUIDNode = SimpleFilterFieldNodeBase & {
    type: 'UID';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField SmartscapeId node.
 * @public
 */
export type SimpleFilterFieldSmartscapeIdNode = SimpleFilterFieldNodeBase & {
    type: 'SmartscapeId';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField Timestamp node.
 * @public
 */
export type SimpleFilterFieldTimestampNode = SimpleFilterFieldNodeBase & {
    type: 'Timestamp';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField string node.
 * @public
 */
export type SimpleFilterFieldStringNode = SimpleFilterFieldNodeBase & {
    type: 'String';
    textValue?: string;
    value: string;
};
/**
 * Type used for defining a FilterField variable node.
 * @public
 */
export type SimpleFilterFieldVariableNode = SimpleFilterFieldNodeBase & {
    type: 'Variable';
    variableType: 'Any';
    textValue?: string;
    value: string;
};
/**
 * Type used for defining a FilterField duration node.
 * @public
 */
export type SimpleFilterFieldDurationNode = SimpleFilterFieldNodeBase & {
    type: 'Duration';
    textValue?: string;
    value?: number;
    unit?: 'ns' | 'ms' | 's' | 'm' | 'h' | 'd';
};
/**
 * Type used for defining a FilterField number node.
 * @public
 */
export type SimpleFilterFieldNumberNode = SimpleFilterFieldNodeBase & {
    type: 'Number';
    textValue?: string;
    value: number;
};
/**
 * Type used for defining a FilterField bigint node.
 * @public
 */
export type SimpleFilterFieldBigIntNode = SimpleFilterFieldNodeBase & {
    type: 'BigInt';
    textValue?: string;
    value: string;
};
/**
 * Type used for defining a FilterField boolean node.
 * @public
 */
export type SimpleFilterFieldBooleanNode = SimpleFilterFieldNodeBase & {
    type: 'Boolean';
    textValue?: string;
    value: boolean;
};
/**
 * Type used for defining a FilterField list node.
 * @public
 */
export type SimpleFilterFieldListNode = SimpleFilterFieldNodeBase & {
    type: 'List';
    textValue?: string;
    value: SimpleFilterFieldLeafNode[];
};
/**
 * Type used for defining a FilterField comparison operator node.
 * @public
 */
export type SimpleFilterFieldComparisonOperatorNode = SimpleFilterFieldNodeBase & {
    type: 'ComparisonOperator';
    textValue?: string;
    value: '=' | '!=' | '<' | '<=' | '>' | '>=' | 'starts-with' | 'ends-with' | 'contains' | 'not-starts-with' | 'not-ends-with' | 'not-contains' | 'matches-phrase' | 'not-matches-phrase';
};
/**
 * Type used for defining a FilterField exists operator node.
 * @public
 */
export type SimpleFilterFieldExistsOperatorNode = SimpleFilterFieldNodeBase & {
    type: 'ExistsOperator';
    textValue?: string;
    value: boolean;
};
/**
 * Type used for defining a FilterField exists operator node.
 * @public
 */
export type SimpleFilterFieldSearchOperatorNode = SimpleFilterFieldNodeBase & {
    type: 'SearchOperator';
    textValue?: '*~' | '* ~';
    value: 'search';
};
/**
 * Type used for defining a FilterField inclusion operator node.
 * @public
 */
export type SimpleFilterFieldInclusionOperatorNode = SimpleFilterFieldNodeBase & {
    type: 'InclusionOperator';
    textValue?: 'in' | 'not in';
    value: 'in' | 'not in';
};
/**
 * Type used for defining a FilterField error node.
 * @public
 */
export type SimpleFilterFieldErrorNode = SimpleFilterFieldNodeBase & {
    type: 'Error';
    textValue?: string;
    value: string | SimpleFilterFieldLeafNode[];
};
/**
 * Type used for defining a FilterField leaf node.
 * @public
 */
export type SimpleFilterFieldLeafNode = SimpleFilterFieldKeyNode | SimpleFilterFieldJSONPathNode | SimpleFilterFieldStringNode | SimpleFilterFieldVariableNode | SimpleFilterFieldNumberNode | SimpleFilterFieldBigIntNode | SimpleFilterFieldBooleanNode | SimpleFilterFieldDurationNode | SimpleFilterFieldIPAddressNode | SimpleFilterFieldUIDNode | SimpleFilterFieldSmartscapeIdNode | SimpleFilterFieldTimestampNode | SimpleFilterFieldComparisonOperatorNode | SimpleFilterFieldExistsOperatorNode | SimpleFilterFieldSearchOperatorNode | SimpleFilterFieldInclusionOperatorNode | SimpleFilterFieldErrorNode;
/**
 * Type used for defining a FilterField value node.
 * @public
 */
export type SimpleFilterFieldValueNode = SimpleFilterFieldLeafNode | SimpleFilterFieldListNode;
/**
 * Type used for defining a FilterField node.
 * @public
 */
export type SimpleFilterFieldNode = SimpleFilterFieldGroupNode | SimpleFilterFieldStatementNode | SimpleFilterFieldListNode | SimpleFilterFieldLeafNode;
/**
 * Type used for defining the FilterField syntax tree.
 * @public
 */
export type SimpleFilterFieldTree = SimpleFilterFieldRootNode | undefined;
